    /// Full filenames (case-sensitive) → Lexilla lexer name.
    /// For files with no extension (Dockerfile, Makefile, etc.) and dotfiles.
    public static let byFilename: [String: String] = [
        ".bashrc": "bash",
        ".editorconfig": "props",
