    ]

    /// Resolve a file URL or filename to a Lexilla lexer name.
    /// Returns `nil` if the file should be shown as plain text.
    public static func lexer(for filename: String) -> String? {
        if let exact = byFilename[filename] { return exact }
        let lower = filename.lowercased()
        if let exact = byFilename[lower] { return exact }
        // Match longest extension suffix (handles e.g. "foo.blade.php" → "blade.php").
        let parts = lower.split(separator: ".")
        if parts.count >= 3 {
            let twoDot = parts.suffix(2).joined(separator: ".")
            if let hit = byExtension[twoDot] { return hit }
        }
        if let dot = lower.lastIndex(of: ".") {
            let ext = String(lower[lower.index(after: dot)...])
            if let hit = byExtension[ext] { return hit }
        }
        return nil
    }
